// Extraer descripción — estrategias por fuente (basado en flujo_enrichment_llm_alquiler v2)
const item = $('Split In Batches').item.json;
const input = $input.first();
const response = input?.json?.body || input?.json || {};
const scrape = response?.data || response;
const html = scrape?.rawHtml || '';
const markdown = scrape?.markdown || '';

let descripcion = '';
let titulo = '';
let metodo = 'none';

if (item.fuente === 'remax') {
  // Remax: parsear atributo data-page="..." del HTML
  if (html && html.length > 500) {
    try {
      const match = html.match(/data-page="([^"]*?)"/i);
      if (match && match[1]) {
        const jsonString = match[1]
          .replace(/&quot;/g, '"')
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>');
        const data = JSON.parse(jsonString);
        const listing = data.props?.listing || data.props?.property || null;
        if (listing) {
          titulo = listing.title || '';
          descripcion = listing.description_website || listing.description || '';
          metodo = 'data-page';
        }
      }
    } catch (e) { console.log('Remax data-page error: ' + e.message); }
  }
  // Fallback: markdown
  if (!descripcion || descripcion.length < 20) {
    if (markdown && markdown.length >= 50) {
      descripcion = markdown.substring(0, 3000);
      metodo = 'markdown_fallback';
    }
  }
} else if (item.fuente === 'century21') {
  // C21: usar markdown directo
  if (markdown && markdown.length >= 50) {
    descripcion = markdown.substring(0, 3000);
    metodo = 'markdown';
  }
}

// Armar contenido final
let contenido = descripcion;
if (item.fuente === 'remax' && titulo && metodo === 'data-page') {
  contenido = 'TÍTULO: ' + titulo + '\n\nDESCRIPCIÓN:\n' + descripcion.substring(0, 3000);
}

if (contenido.length > 3000) contenido = contenido.substring(0, 3000);

console.log(`Prop ${item.id} (${item.fuente}): método=${metodo}, descripción=${contenido.length} chars`);

return [{ json: { ...item, descripcion: contenido, metodo_extraccion: metodo, firecrawl_error: contenido.length === 0 } }];

// Parse & validate LLM response
const itemInput = $input.first().json;
// Solo UNA de las dos ramas corrió — try/catch porque $() tira error si el nodo no ejecutó
let upstream = null;
try { upstream = $('Build Prompt Casa').first().json; } catch (e) {}
if (!upstream) {
  try { upstream = $('Build Prompt Terreno').first().json; } catch (e) {}
}
if (!upstream) upstream = {};
const tipo_prompt = upstream.tipo_prompt || 'casa';

const text = itemInput?.content?.[0]?.text || '';
const tokens = (itemInput?.usage?.input_tokens || 0) + (itemInput?.usage?.output_tokens || 0);

let jsonStr = text;
const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) jsonStr = jsonMatch[1].trim();
else {
  const braceMatch = text.match(/\{[\s\S]*\}/);
  if (braceMatch) jsonStr = braceMatch[0];
}

let datos_llm, errores = [], requiere_revision = false;
try {
  datos_llm = JSON.parse(jsonStr);
} catch (e) {
  errores.push('json_parse_error: ' + e.message);
  requiere_revision = true;
  datos_llm = null;
}

if (datos_llm) {
  const VALID_TC = ['paralelo', 'oficial', 'no_especificado'];
  if (datos_llm.tipo_cambio_detectado && !VALID_TC.includes(datos_llm.tipo_cambio_detectado)) {
    errores.push('tipo_cambio_invalido');
    datos_llm.tipo_cambio_detectado = 'no_especificado';
  }

  if (tipo_prompt === 'casa') {
    const VALID_ESTADOS = ['entrega_inmediata', 'preventa'];
    if (datos_llm.estado_construccion && !VALID_ESTADOS.includes(datos_llm.estado_construccion)) {
      errores.push('estado_construccion_invalido');
      datos_llm.estado_construccion = null;
    }
    if (datos_llm.dormitorios != null && (datos_llm.dormitorios < 0 || datos_llm.dormitorios > 10)) {
      errores.push('dormitorios_fuera_rango'); datos_llm.dormitorios = null;
    }
    if (datos_llm.banos != null && (datos_llm.banos < 0 || datos_llm.banos > 10)) {
      errores.push('banos_fuera_rango'); datos_llm.banos = null;
    }
    if (datos_llm.niveles != null && (datos_llm.niveles < 1 || datos_llm.niveles > 5)) {
      errores.push('niveles_fuera_rango'); datos_llm.niveles = null;
    }
    if (!Array.isArray(datos_llm.ambientes_adicionales)) datos_llm.ambientes_adicionales = [];
    if (!Array.isArray(datos_llm.amenities_confirmados)) datos_llm.amenities_confirmados = [];
    if (!Array.isArray(datos_llm.equipamiento_detectado)) datos_llm.equipamiento_detectado = [];
  } else {
    if (datos_llm.area_terreno_m2 != null && (datos_llm.area_terreno_m2 < 20 || datos_llm.area_terreno_m2 > 50000)) {
      errores.push('area_terreno_fuera_rango'); datos_llm.area_terreno_m2 = null;
    }
    if (datos_llm.frente_m != null && (datos_llm.frente_m < 3 || datos_llm.frente_m > 500)) {
      errores.push('frente_fuera_rango'); datos_llm.frente_m = null;
    }
    if (datos_llm.fondo_m != null && (datos_llm.fondo_m < 3 || datos_llm.fondo_m > 500)) {
      errores.push('fondo_fuera_rango'); datos_llm.fondo_m = null;
    }
    if (!Array.isArray(datos_llm.servicios_disponibles)) datos_llm.servicios_disponibles = [];
  }

  if (errores.length > 2) requiere_revision = true;
}

return [{
  json: {
    ...upstream,
    descripcion: upstream.descripcion || '',
    tipo_prompt,
    datos_llm,
    tokens_usados: tokens,
    errores,
    requiere_revision
  }
}];

// === MERGE LIGERO — Casas/Terrenos v1.1 ===
// Calcula precio_usd desde BOB + valida zona (GPS polígono + descripción)

const item = $input.first().json;
const tcData = $('Cargar TC').first().json.tc;
const tcOficial = parseFloat(tcData?.oficial?.valor) || 6.96;
const tcParalelo = parseFloat(tcData?.paralelo?.valor) || 9.34;

const llm = item.datos_llm || {};
const tipoTC = llm.tipo_cambio_detectado || 'no_especificado';

let precio_usd = null;
let tc_usado = null;
let depende_de_tc = false;

if (item.moneda_original === 'BOB' && item.precio_usd_original) {
  const bob = parseFloat(item.precio_usd_original);
  if (tipoTC === 'paralelo') {
    precio_usd = Math.round(bob / tcParalelo * 100) / 100;
    tc_usado = tcParalelo;
    depende_de_tc = true;
  } else {
    precio_usd = Math.round(bob / tcOficial * 100) / 100;
    tc_usado = tcOficial;
    depende_de_tc = (tipoTC === 'oficial');
  }
} else if (item.moneda_original === 'USD') {
  precio_usd = parseFloat(item.precio_usd_original);
}

const area_terreno = llm.area_terreno_m2 || item.area_terreno_m2 || null;
const frente = item.tipo_prompt === 'terreno' ? (llm.frente_m || null) : null;
const fondo = item.tipo_prompt === 'terreno' ? (llm.fondo_m || null) : null;

const datos_json_enrichment = {
  llm_output: llm,
  llm_metadata: {
    modelo: 'claude-haiku-4-5-20251001',
    tokens: item.tokens_usados,
    fecha: new Date().toISOString(),
    version: 'v1.1',
    tipo_prompt: item.tipo_prompt,
    requiere_revision: item.requiere_revision,
    errores_validacion: item.errores
  },
  descripcion: item.descripcion,
  tc_conversion: {
    moneda_original: item.moneda_original,
    precio_bob_original: item.moneda_original === 'BOB' ? item.precio_usd_original : null,
    tc_detectado: tipoTC,
    tc_usado: tc_usado,
    precio_usd_calculado: precio_usd
  }
};

// === VALIDACIÓN DOBLE DE ZONA (v1.1) ===
const descripcion = item.descripcion || '';
const confirmaEquipetrol = /equipetrol|sirari|villa brig[ií]da/i.test(descripcion);
const dentroPoligono = !!item.zona;

let statusFinal = 'completado';
let razonInactiva = null;

if (!dentroPoligono && !confirmaEquipetrol) {
  statusFinal = 'excluida_zona';
  razonInactiva = 'GPS fuera polígono + descripción no menciona Equipetrol';
} else if (dentroPoligono && !confirmaEquipetrol) {
  statusFinal = 'excluida_zona';
  razonInactiva = 'GPS dentro pero descripción no confirma Equipetrol (GPS portal falso)';
} else if (!dentroPoligono && confirmaEquipetrol) {
  razonInactiva = 'GPS fuera polígono pero descripción menciona Equipetrol — revisar';
}

console.log();

return [{
  json: {
    id: item.id,
    precio_usd,
    tipo_cambio_usado: tc_usado,
    tipo_cambio_detectado: tipoTC,
    depende_de_tc,
    area_terreno_m2: area_terreno,
    frente_m: frente,
    fondo_m: fondo,
    dormitorios: item.tipo_prompt === 'casa' ? (llm.dormitorios ?? item.dormitorios) : null,
    banos: item.tipo_prompt === 'casa' ? (llm.banos ?? item.banos) : null,
    estado_construccion: llm.estado_construccion || null,
    datos_json_enrichment: JSON.stringify(datos_json_enrichment),
    status_final: statusFinal,
    razon_inactiva: razonInactiva
  }
}];

const all = $input.all().map(i => i.json);
const total = all.length;
console.log(`=== ENRICHMENT CASAS/TERRENOS COMPLETADO ===\nProps procesadas: ${total}`);
return [{ json: { timestamp: new Date().toISOString(), workflow: 'enrichment_casas_terrenos', version: '1.0.0', total_procesadas: total, status: 'completado' } }];
